arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 returns null for empty env vars on Linux, so check
        // existence via GetEnvironmentVariables() to preserve the
        // "not set" vs "explicitly empty" distinction.
        var envVars = Environment.GetEnvironmentVariables();
        if (!envVars.Contains("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

